//! Repository for RequestForQuotation entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below hold the hand-written RequestForQuotation SQL (4-layer rule: services orchestrate, repos
//! hold SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<RequestForQuotation, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::RequestForQuotation;

/// Table name for RequestForQuotation entities
pub const TABLE_NAME: &str = "buying.request_for_quotations";

/// Repository for RequestForQuotation entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct RequestForQuotationRepository(
    backbone_orm::GenericCrudRepository<RequestForQuotation, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for RequestForQuotationRepository {
    type Target = backbone_orm::GenericCrudRepository<RequestForQuotation, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl RequestForQuotationRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// The exact row an RFQ header insert writes.
///
/// `status` and `rfq_date` are not fields — the INSERT hard-codes `'submitted'` and `CURRENT_DATE`.
pub struct NewRfqRow<'a> {
    pub id: Uuid,
    pub rfq_number: &'a str,
    pub material_request_id: Uuid,
    pub company_id: Uuid,
    pub response_due: Option<chrono::NaiveDate>,
}

/// An RFQ's convertibility state, as read by the RFQ→SupplierQuotation funnel step.
pub struct RfqSourceRow {
    pub company_id: Uuid,
    pub status: String,
}

/// Hand-written RequestForQuotation SQL. Lives here (not in the write service) per the module's
/// 4-layer rule.
impl RequestForQuotationRepository {
    /// Insert an RFQ header as `submitted`, dated today.
    ///
    /// Takes the CALLER'S connection so the header, its lines, its invited suppliers and the source
    /// MR's status flip all commit as one unit. The caller has already bound the company on it
    /// (`bind_company_on`) — don't re-bind here.
    ///
    /// Returns the raw `sqlx::Error` deliberately: the caller inspects it for a unique violation to
    /// turn a duplicate RFQ number into a domain error.
    pub async fn insert_rfq(
        &self,
        conn: &mut sqlx::PgConnection,
        r: &NewRfqRow<'_>,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            r#"INSERT INTO buying.request_for_quotations
                (id, rfq_number, material_request_id, company_id, status, rfq_date, response_due)
               VALUES ($1,$2,$3,$4,'submitted'::purchase_doc_status,CURRENT_DATE,$5)"#,
        )
        .bind(r.id).bind(r.rfq_number).bind(r.material_request_id).bind(r.company_id)
        .bind(r.response_due)
        .execute(conn)
        .await?;
        Ok(())
    }

    /// Read an RFQ's company + status for the RFQ→SupplierQuotation conversion. `Ok(None)` = not
    /// found. ID-only + scoped read — see [`super::MaterialRequestRepository::fetch_source`].
    pub async fn fetch_source(
        &self,
        pool: &PgPool,
        rfq_id: Uuid,
    ) -> Result<Option<RfqSourceRow>, sqlx::Error> {
        let row = company_scope::fetch_optional_row_scoped(
            pool,
            sqlx::query(
                r#"SELECT company_id, status::text AS st FROM buying.request_for_quotations
                   WHERE id=$1 AND (metadata->>'deleted_at') IS NULL"#,
            ).bind(rfq_id),
        )
        .await?;
        Ok(row.map(|r| RfqSourceRow {
            company_id: r.get("company_id"),
            status: r.get("st"),
        }))
    }
}

backbone_core::impl_crud_repository!(RequestForQuotationRepository, RequestForQuotation, soft_delete);
